// Refs: 'PL Fetch Invoices'
const invoices = $input.first().json.items;
const today = new Date().toISOString().split('T')[0];

const results = {
  paid: [],
  overdue: [],
  upcoming: []
};

for (const inv of invoices) {
  if (inv.draft) continue;

  if (inv.paid) {
    results.paid.push(inv);
  } else if (inv.deadline < today) {
    results.overdue.push(inv);
  } else {
    results.upcoming.push(inv);
  }
}

return [{
  json: {
    total_invoices: invoices.length,
    paid_count: results.paid.length,
    overdue_count: results.overdue.length,
    upcoming_count: results.upcoming.length,
    paid: results.paid,
    overdue: results.overdue,
    has_updates: results.paid.length > 0 || results.overdue.length > 0
  }
}];

// Refs: 'Code Filter Status Changes'
const data = $input.first().json;
const lines = ['📊 Pennylane Invoice Status Report', ''];

if (data.paid_count > 0) {
  lines.push(`✅ ${data.paid_count} invoice(s) paid:`);
  for (const inv of data.paid) {
    lines.push(`  - ${inv.invoice_number} | ${inv.currency_amount} ${inv.currency} | ${inv.label}`);
  }
  lines.push('');
}

if (data.overdue_count > 0) {
  lines.push(`⚠️ ${data.overdue_count} invoice(s) overdue:`);
  for (const inv of data.overdue) {
    lines.push(`  - ${inv.invoice_number} | ${inv.currency_amount} ${inv.currency} | Due: ${inv.deadline} | ${inv.label}`);
  }
  lines.push('');
}

lines.push(`📋 ${data.upcoming_count} invoice(s) upcoming`);
lines.push(`Total tracked: ${data.total_invoices}`);

return [{
  json: {
    message: lines.join('\n'),
    paid_count: data.paid_count,
    overdue_count: data.overdue_count,
    upcoming_count: data.upcoming_count
  }
}];
